#!/bin/bash

# Phase 1 - Load Testing Script
# Performs basic load testing using Apache Bench or k6\nset -e

# Colors\nRED='\033[0;31m'\nGREEN='\033[0;32m'\nYELLOW='\033[1;33m'\nBLUE='\033[0;34m'\nCYAN='\033[0;36m'\nNC='\033[0m'

# Configuration\nAPI_BASE=\"http://localhost:5000/api\"\nNUM_REQUESTS=100\nCONCURRENCY=10\n\nprint_header() {\n    echo \"\"\n    echo -e \"${CYAN}════════════════════════════════════════════════════════════${NC}\"\n    echo -e \"${CYAN}  $1${NC}\"\n    echo -e \"${CYAN}════════════════════════════════════════════════════════════${NC}\"\n    echo \"\"\n}\n\nprint_test() {\n    echo -e \"${BLUE}[LOAD TEST]${NC} $1\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}[✓]${NC} $1\"\n}\n\nprint_error() {\n    echo -e \"${RED}[✗]${NC} $1\"\n}\n\ncheck_tools() {\n    print_header \"Checking Load Testing Tools\"\n    \n    if command -v ab &> /dev/null; then\n        print_success \"Apache Bench found\"\n        return 0\n    elif command -v k6 &> /dev/null; then\n        print_success \"k6 found\"\n        return 0\n    else\n        print_error \"Neither Apache Bench nor k6 found\"\n        print_error \"Install: sudo apt-get install apache2-utils\"\n        echo \"Or: npm install -g k6\"\n        exit 1\n    fi\n}\n\ntest_with_apache_bench() {\n    print_header \"Load Testing with Apache Bench\"\n    \n    print_test \"Health Check Endpoint\"\n    echo \"Requests: $NUM_REQUESTS | Concurrency: $CONCURRENCY\"\n    ab -n $NUM_REQUESTS -c $CONCURRENCY http://localhost:5000/health\n    \n    echo \"\"\n    print_test \"Video List Endpoint\"\n    ab -n $NUM_REQUESTS -c $CONCURRENCY \"$API_BASE/videos?limit=10\"\n    \n    echo \"\"\n    print_test \"User Search Endpoint\"\n    ab -n $NUM_REQUESTS -c $CONCURRENCY \"$API_BASE/users/search?query=test\"\n}\n\ntest_with_k6() {\n    print_header \"Load Testing with k6\"\n    \n    # Create k6 test script\n    local test_script=\"/tmp/k6-test-$$.js\"\n    cat > \"$test_script\" << 'EOF'\nimport http from 'k6/http';\nimport { check, sleep } from 'k6';\n\nexport let options = {\n  vus: 10,\n  duration: '30s',\n};\n\nexport default function() {\n  // Test health endpoint\n  let res1 = http.get('http://localhost:5000/health');\n  check(res1, {\n    'Health status is 200': (r) => r.status === 200,\n    'Health response time < 500ms': (r) => r.timings.duration < 500,\n  });\n\n  // Test video list\n  let res2 = http.get('http://localhost:5000/api/videos?limit=10');\n  check(res2, {\n    'Videos status is 200': (r) => r.status === 200,\n    'Videos response time < 1000ms': (r) => r.timings.duration < 1000,\n  });\n\n  // Test user search\n  let res3 = http.get('http://localhost:5000/api/users/search?query=test');\n  check(res3, {\n    'Search status is 200': (r) => r.status === 200,\n  });\n\n  sleep(1);\n}\nEOF\n    \n    print_test \"Running k6 load test (30 seconds)\"\n    k6 run \"$test_script\"\n    \n    rm -f \"$test_script\"\n}\n\nrun_stress_test() {\n    print_header \"Stress Testing\"\n    \n    print_test \"Simulating 50 concurrent users\"\n    if command -v ab &> /dev/null; then\n        ab -n 500 -c 50 http://localhost:5000/health\n    else\n        print_error \"Apache Bench required for stress test\"\n    fi\n}\n\nprint_results_interpretation() {\n    print_header \"Understanding Results\"\n    \n    echo -e \"${YELLOW}Key Metrics:${NC}\"\n    echo \"\"\n    echo \"  Requests per second (RPS/Throughput)\"\n    echo \"    • Higher is better\"\n    echo \"    • Target: > 100 RPS for healthy API\"\n    echo \"\"\n    echo \"  Response Time (Mean)\"\n    echo \"    • Lower is better\"\n    echo \"    • Target: < 200ms for API endpoints\"\n    echo \"\"\n    echo \"  Failed Requests\"\n    echo \"    • Should be 0 under normal load\"\n    echo \"    • If > 0, check server logs\"\n    echo \"\"\n    echo \"  50th/95th/99th Percentile Response Times\"\n    echo \"    • Shows performance under different conditions\"\n    echo \"    • 99th percentile should be < 2x mean time\"\n    echo \"\"\n}\n\nmain() {\n    print_header \"PHASE 1 - LOAD TESTING\"\n    \n    echo -e \"${YELLOW}This test will:${NC}\"\n    echo \"  • Test API endpoints under load\"\n    echo \"  • Measure response times\"\n    echo \"  • Check for failed requests\"\n    echo \"  • Simulate concurrent users\"\n    echo \"\"\n    read -p \"Continue? (yes/no): \" confirm\n    if [ \"$confirm\" != \"yes\" ]; then\n        echo \"Load testing cancelled\"\n        exit 0\n    fi\n    \n    # Check if API is available\n    print_header \"Pre-Test Checks\"\n    if curl -s -f http://localhost:5000/health > /dev/null 2>&1; then\n        print_success \"API Server is responding\"\n    else\n        print_error \"API Server is not responding on http://localhost:5000\"\n        exit 1\n    fi\n    \n    check_tools\n    \n    # Run appropriate test\n    if command -v ab &> /dev/null; then\n        test_with_apache_bench\n    elif command -v k6 &> /dev/null; then\n        test_with_k6\n    fi\n    \n    print_results_interpretation\n}\n\nmain\n